extension.valueString:
/*
@input: Client's age is less than 6 months
@pseudocode: Today's date − "Date of birth" < 6 months
@code: Client's age is less than 6 months-41
@decision: IMMZ.D2.DT.Measles.MCV dose 0: Measles-containing vaccine dose 0 (MCV0) administration
*/
define "Client's age is less than 6 months":
  Encounter."Current Patient Age In Months" < 6

/*
@output: Client is not due for MCV0 Case 1
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for MCV0 Case 1":
  Encounter."Client's age is less than 6 months"

/*
@internal: MCV Dose 0 Doses Administered to Patient
*/
define "MCV Dose 0 Doses Administered to Patient":
  "MCV Doses Administered to Patient".seriesDose0()

/*
@internal: MCV Dose 0 Doses Administered to Patient
*/
define "MCV Dose 0 Doses Administered to Patient":
  MeaslesElements."MCV Dose 0 Doses Administered to Patient".onOrBefore(Today)

/*
@internal: Number of MCV Dose 0 Doses Administered
*/
define "Number of MCV Dose 0 Doses Administered":
  Count("MCV Dose 0 Doses Administered to Patient")

/*
@input: MCV0 was not administered
@pseudocode: Count of vaccines administered (where "Vaccine type" = "Measles-containing vaccines" and "Type of dose" = "Dose 0") = 0
@code: MCV0 was not administered-119
@decision: IMMZ.D2.DT.Measles.MCV dose 0: Measles-containing vaccine dose 0 (MCV0) administration
*/
define "MCV0 was not administered":
  "Number of MCV Dose 0 Doses Administered" = 0

/*
@input: Client's age is between 6 months and 9 months
@pseudocode: 6 months ≤ Today's date − "Date of birth" < 9 months
@code: Client's age is between 6 months and 9 months-52
@decision: IMMZ.D2.DT.Measles.MCV dose 0: Measles-containing vaccine dose 0 (MCV0) administration
*/
define "Client's age is between 6 months and 9 months":
  6 <= Encounter."Current Patient Age In Months"
  and Encounter."Current Patient Age In Months" < 9

/*
  @dataElement: Live attenuated vaccines
*/
define "Live Attenuated Vaccines":
  "Doses Administered to Patient" I 
    where I.vaccineCode in Concepts."Live Attenuated"

/*
@dataElement Live attenuated vaccines
*/
define "Live Attenuated Vaccines":
  Elements."Live Attenuated Vaccines" I
    where I.occurrence.toInterval() same day or before Today

/*
@dataElement Date and time of last live attenuated vaccine
*/
define "Date of Latest Live Attenuated Vaccine":
  date from start of "Live Attenuated Vaccines".mostRecent().occurrence.toInterval()

/*
@input: Live vaccine was administered in the last 4 weeks
@pseudocode: Today's date − latest "Date and time of vaccination" (where "Live vaccine" = TRUE) < 4 weeks
*/
define "Live vaccine was administered in the last 4 weeks":
	"Date of Latest Live Attenuated Vaccine" is not null 
    and duration in weeks between "Date of Latest Live Attenuated Vaccine" and Today < 4

/*
@input: Live vaccine was administered in the last 4 weeks
@pseudocode: Today's date − latest "Date and time of vaccination" (where "Live vaccine" = TRUE) < 4 weeks
@code: Live vaccine was administered in the last 4 weeks-92
@decision: IMMZ.D2.DT.Measles.Ongoing transmission: Countries with ongoing transmission in which the risk of measles mortality remains high (countries that provide first dose of measles-containing vaccine (MCV) at 9 months and second dose of MCV at 15 months)
@decision: IMMZ.D2.DT.Measles.Low transmission: Countries with low levels of measles transmission (countries that provide first dose of measles-containing vaccine (MCV) at 12 months and second dose of MCV at 15 months)
@decision: IMMZ.D2.DT.Measles.MCV dose 0: Measles-containing vaccine dose 0 (MCV0) administration
*/
define "Live vaccine was administered in the last 4 weeks":
  Encounter."Live vaccine was administered in the last 4 weeks"

/*
@output: Client is not due for MCV0 Case 2
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for MCV0 Case 2":
  Encounter."MCV0 was not administered"
    and Encounter."Client's age is between 6 months and 9 months"
    and Encounter."Live vaccine was administered in the last 4 weeks"

/*
@input: Client's age is more than or equal to 9 months
@pseudocode: Today's date − "Date of birth" ≥ 9 months
@code: Client's age is more than or equal to 9 months-41
@decision: IMMZ.D2.DT.Measles.Ongoing transmission: Countries with ongoing transmission in which the risk of measles mortality remains high (countries that provide first dose of measles-containing vaccine (MCV) at 9 months and second dose of MCV at 15 months)
@decision: IMMZ.D2.DT.Measles.MCV dose 0: Measles-containing vaccine dose 0 (MCV0) administration
*/
define "Client's age is more than or equal to 9 months":
  Encounter."Current Patient Age In Months" >= 9

/*
@output: Client is not due for MCV0 Case 3
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for MCV0 Case 3":
  Encounter."Client's age is more than or equal to 9 months"

/*
@input: MCV0 was administered
@pseudocode: Count of vaccines administered (where "Vaccine type" = "Measles-containing vaccines" and "Type of dose" = "Dose 0") = 1
@code: MCV0 was administered-119
@decision: IMMZ.D2.DT.Measles.MCV dose 0: Measles-containing vaccine dose 0 (MCV0) administration
*/
define "MCV0 was administered":
  "Number of MCV Dose 0 Doses Administered" = 1

/*
@output: Client is not due for MCV0 Case 4
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for MCV0 Case 4":
  Encounter."MCV0 was administered"

/*
@output: Client is not due for MCV0
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for MCV0":
  "Client is not due for MCV0 Case 1"
    or "Client is not due for MCV0 Case 2"
    or "Client is not due for MCV0 Case 3"
    or "Client is not due for MCV0 Case 4"

/*
@output: Client is not due for MCV0 Guidance
@guidance = Should not vaccinate client with MCV0 as client's age is less than 6 months. Check for any vaccines due and inform the caregiver of when to come back for MCV0.
@guidance = Should not vaccinate client with MCV0 as live vaccine was administered in the past 4 weeks. Check for any vaccines due and inform the caregiver of when to come back for MCV0.
@guidance = Should not vaccinate client with MCV0 as client's age is more than 9 months.
Check measles routine immunization schedule.
@guidance = MCV0 was administered.
Check measles routine immunization schedule.
*/
define "Client is not due for MCV0 Guidance":
  case
    when "Client is not due for MCV0 Case 1" then 'Should not vaccinate client with MCV0 as client\'s age is less than 6 months. Check for any vaccines due and inform the caregiver of when to come back for MCV0.'
    when "Client is not due for MCV0 Case 2" then 'Should not vaccinate client with MCV0 as live vaccine was administered in the past 4 weeks. Check for any vaccines due and inform the caregiver of when to come back for MCV0.'
    when "Client is not due for MCV0 Case 3" then 'Should not vaccinate client with MCV0 as client\'s age is more than 9 months.
Check measles routine immunization schedule.'
    when "Client is not due for MCV0 Case 4" then 'MCV0 was administered.
Check measles routine immunization schedule.'
    else ''
  end

/*
@input: No live vaccine was administered in the last 4 weeks
@pseudocode: Today's date − latest "Date and time of vaccination" (where "Live vaccine" = TRUE) ≥ 4 weeks
*/
define "No live vaccine was administered in the last 4 weeks":
  not("Live vaccine was administered in the last 4 weeks")

/*
@input: No live vaccine was administered in the last 4 weeks
@pseudocode: Today's date − latest "Date and time of vaccination" (where "Live vaccine" = TRUE) ≥ 4 weeks
@code: No live vaccine was administered in the last 4 weeks-92
@decision: IMMZ.D2.DT.Measles.Ongoing transmission: Countries with ongoing transmission in which the risk of measles mortality remains high (countries that provide first dose of measles-containing vaccine (MCV) at 9 months and second dose of MCV at 15 months)
@decision: IMMZ.D2.DT.Measles.Low transmission: Countries with low levels of measles transmission (countries that provide first dose of measles-containing vaccine (MCV) at 12 months and second dose of MCV at 15 months)
@decision: IMMZ.D2.DT.Measles.MCV dose 0: Measles-containing vaccine dose 0 (MCV0) administration
*/
define "No live vaccine was administered in the last 4 weeks":
  Encounter."No live vaccine was administered in the last 4 weeks"

/*
@output: Consider MCV0.
@pseudocode: Create a clinical note.
"Immunization recommendation status" = "Further evaluation needed"
*/
define "Consider MCV0.":
  Encounter."MCV0 was not administered"
    and Encounter."Client's age is between 6 months and 9 months"
    and Encounter."No live vaccine was administered in the last 4 weeks"

/*
@output: Consider MCV0. Guidance
@guidance: May vaccinate client with MCV0 as client is within appropriate age range, MCV0 was not administered and no live vaccine was administered in the past 4 weeks. Check if one of the MCV0 specific scenarios is applicable.
*/
define "Consider MCV0. Guidance":
  'May vaccinate client with MCV0 as client is within appropriate age range, MCV0 was not administered and no live vaccine was administered in the past 4 weeks. Check if one of the MCV0 specific scenarios is applicable.'
